        chip: "Mismatch",
        runtime: "Ad pixel blocked",
        record: "ads=no",
        signal: "Conflict logged",
        primary: "Block tag",
        secondary: "Open audit",
        status: "Runtime mismatch state verifies actual storage and tag behavior against the consent record.",
