type QrScanMode =
  | "unsupported"
  | "preScan"
  | "delegatedScanner"
  | "permission"
  | "cameraReady"
  | "aimGuide"
  | "torch"
  | "focus"
  | "lowLight"
  | "noCode"
  | "multipleCodes"
  | "decoding"
  | "decodedPreview"
  | "unsafeUrl"
  | "expiredPayload"
  | "duplicateScan"
  | "scanFromPhoto"
  | "manualCode"
  | "success"
  | "cleanup"
  | "offlineValidation";

type QrScanBadMode =
  | "autoOpenUrl"
  | "cameraOnlyDeadEnd"
  | "wrongCodeSelected"
  | "spinnerNoGuidance"
  | "noPayloadPreview"
  | "secretRetained"
  | "repeatedAction";

