function QrGlyph({ variant = "target" }: { variant?: "target" | "found" | "warning" }) {
  return (
    <div className={`qr-scan-code is-${variant}`} aria-hidden="true">
      {Array.from({ length: 25 }).map((_, index) => (
        <span key={index}></span>
      ))}
    </div>
  );
}

