function HapticMeter({ intensity }: { intensity: number }) {
  return (
    <div className="haptic-meter" aria-hidden="true">
      {Array.from({ length: 5 }).map((_, index) => (
        <span key={index} className={index < intensity ? "active" : ""}></span>
      ))}
    </div>
  );
}

