type CalendarEvent = {
  id: string;
  day: number;
  title: string;
  time: string;
  end: string;
  status: "Confirmed" | "Tentative" | "Cancelled" | "Conflict" | "All day";
  calendar: string;
  location: string;
  notes: string;
};

