type NextActionState = "ready" | "review" | "accepted" | "deferred" | "dismissed" | "alreadyDone" | "stale" | "blocked" | "lowConfidence";
type RecommendedAction = {
  id: string;
  title: string;
  source: string;
  trigger: string;
  evidence: string;
  consequence: string;
  confidence: string;
  owner: string;
  due: string;
  state: NextActionState;
};

