type HumanApprovalGateState = "paused" | "eligible" | "selfReview" | "approved" | "edit" | "rejected" | "canceled" | "timeout" | "stale" | "bypass" | "failedResume" | "mobile";

type HumanApprovalGateCopy = {
  title: string;
  status: string;
  tone: "ready" | "working" | "warning" | "danger";
  action: string;
  payload: string;
  rule: string;
  approver: string;
  next: string;
  facts: string[];
};

